import{_ as e,o as a,c as i,ag as o}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse('{"title":"Test Email and Simulation","description":"","frontmatter":{},"headers":[],"relativePath":"features/test-simulate.md","filePath":"features/test-simulate.md"}'),n={name:"features/test-simulate.md"};function r(s,t,l,d,u,c){return a(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="test-email-and-simulation" tabindex="-1">Test Email and Simulation <a class="header-anchor" href="#test-email-and-simulation" aria-label="Permalink to &quot;Test Email and Simulation&quot;">​</a></h1><p>SendGrail provides two tools for verifying your email configuration: <strong>Test Email</strong> sends a real message, while <strong>Email Simulation</strong> performs a dry run to validate routing and connection resolution without delivering anything.</p><h2 id="test-email" tabindex="-1">Test Email <a class="header-anchor" href="#test-email" aria-label="Permalink to &quot;Test Email&quot;">​</a></h2><p>The test email feature sends an actual email through your configured SMTP connection to verify end-to-end delivery.</p><h3 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Connection</strong></td><td>Select a specific connection or use the default</td></tr><tr><td><strong>Recipient</strong></td><td>The email address to send the test to</td></tr><tr><td><strong>Subject</strong></td><td>Custom subject line for the test email</td></tr><tr><td><strong>Message</strong></td><td>Custom message body</td></tr></tbody></table><h3 id="what-gets-sent" tabindex="-1">What Gets Sent <a class="header-anchor" href="#what-gets-sent" aria-label="Permalink to &quot;What Gets Sent&quot;">​</a></h3><p>The test email is an HTML-formatted message containing your custom message along with a verification notice confirming that the email was sent through SendGrail. This helps the recipient (typically yourself) confirm delivery and rendering.</p><h3 id="fallback-detection" tabindex="-1">Fallback Detection <a class="header-anchor" href="#fallback-detection" aria-label="Permalink to &quot;Fallback Detection&quot;">​</a></h3><p>If your selected connection fails and the email is delivered via a fallback mechanism, SendGrail reports this in the test result. This alerts you that your primary connection may have an issue even though the email was ultimately delivered.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>After setting up a new connection, always send a test email to confirm it works before relying on it for production traffic.</p></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Test emails are real emails and will appear in your email log. They count toward your provider&#39;s sending limits.</p></div><h2 id="email-simulation" tabindex="-1">Email Simulation <a class="header-anchor" href="#email-simulation" aria-label="Permalink to &quot;Email Simulation {#email-simulation}&quot;">​</a></h2><p>Email simulation is a <strong>dry-run mode</strong> that evaluates your configuration without sending any email. It is accessible via the <strong>Simulate</strong> button on the Test Email page.</p><h3 id="what-simulation-reports" tabindex="-1">What Simulation Reports <a class="header-anchor" href="#what-simulation-reports" aria-label="Permalink to &quot;What Simulation Reports&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Output</th><th>Description</th></tr></thead><tbody><tr><td><strong>Connection</strong></td><td>Which SMTP connection would be used</td></tr><tr><td><strong>From Email</strong></td><td>The resolved sender email address</td></tr><tr><td><strong>From Name</strong></td><td>The resolved sender display name</td></tr><tr><td><strong>Tracking Flags</strong></td><td>Whether open tracking and click tracking would be applied</td></tr><tr><td><strong>Routing Rule Match</strong></td><td>Which routing rule matched (if any), or indicates default routing</td></tr></tbody></table><h3 id="when-to-use-simulation" tabindex="-1">When to Use Simulation <a class="header-anchor" href="#when-to-use-simulation" aria-label="Permalink to &quot;When to Use Simulation&quot;">​</a></h3><ul><li><strong>Verify routing rules</strong> -- Confirm that a specific email would be routed to the correct connection based on your rules</li><li><strong>Check connection resolution</strong> -- See which connection would handle the email without risking a delivery failure</li><li><strong>Debug configuration</strong> -- Identify unexpected behavior in your routing or connection setup</li></ul><details class="details custom-block"><summary>Example workflow</summary><ol><li>Create a routing rule that sends WooCommerce emails through Postmark</li><li>Open the Test Email page and click <strong>Simulate</strong></li><li>Enter a subject containing &quot;order&quot; and run the simulation</li><li>Confirm the output shows the Postmark connection and the correct routing rule</li><li>Once satisfied, send a real test email to verify delivery</li></ol></details>',19)])])}const g=e(n,[["render",r]]);export{m as __pageData,g as default};
